const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function chargePayment(message) {
  const { paymentId, amount, currency, customerId, source, metadata } = message;

  console.log(`[PAYMENT] Charging payment`, {
    paymentId,
    amount,
    currency,
    customerId,
    source,
    metadata,
  });

  await new Promise((resolve) => setTimeout(resolve, 250));

  console.log(`[PAYMENT] Charge complete`, { paymentId });
}

async function refundPayment(message) {
  const { paymentId, refundId, amount, currency, reason, metadata } = message;

  console.log(`[PAYMENT] Refunding payment`, {
    paymentId,
    refundId,
    amount,
    currency,
    reason,
    metadata,
  });

  await new Promise((resolve) => setTimeout(resolve, 250));

  console.log(`[PAYMENT] Refund complete`, { paymentId, refundId });
}

async function capturePayment(message) {
  const { paymentId, authorizationId, amount, currency, metadata } = message;

  console.log(`[PAYMENT] Capturing payment`, {
    paymentId,
    authorizationId,
    amount,
    currency,
    metadata,
  });

  await new Promise((resolve) => setTimeout(resolve, 250));

  console.log(`[PAYMENT] Capture complete`, { paymentId, authorizationId });
}

async function processPaymentEvent(message) {
  const eventType = message.eventType || message.type || message.action;

  switch (eventType) {
    case 'payment.charge':
    case 'charge':
      await chargePayment(message);
      break;
    case 'payment.refund':
    case 'refund':
      await refundPayment(message);
      break;
    case 'payment.capture':
    case 'capture':
      await capturePayment(message);
      break;
    default:
      throw new Error(`Unsupported payment event type: ${eventType}`);
  }
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  channel.prefetch(PREFETCH);

  console.log(`[RABBITMQ] Connected. Waiting for messages on queue "${QUEUE_NAME}"`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        const raw = msg.content.toString('utf8');
        const payload = JSON.parse(raw);

        console.log(`[RABBITMQ] Received message`, payload);

        await processPaymentEvent(payload);

        channel.ack(msg);
      } catch (error) {
        console.error(`[RABBITMQ] Failed to process message`, error);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    try {
      console.log(`[SYSTEM] Shutting down consumer...`);
      await channel.close();
      await connection.close();
      process.exit(0);
    } catch (err) {
      console.error(`[SYSTEM] Error during shutdown`, err);
      process.exit(1);
    }
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

startConsumer().catch((err) => {
  console.error(`[SYSTEM] Consumer failed to start`, err);
  process.exit(1);
});